    private static class ShoppingTaskBuilder {
        String mTaskName;
        private Random mRandom = new Random(2);

        ShoppingTaskBuilder withName(String name) {
            mTaskName = name;
            return this;
        }

        ShoppingTask build(int productSize) {
            List<ProductInfo> productList = new ArrayList<>();
            for (int i = 0; i < productSize; i++) {
                float price = mRandom.nextInt(500) * 1.f;
                ProductInfo productInfo;
                if (i < mTaskName.length()) {
                    productInfo = new ProductInfo.Builder()
                                          .withName(String.valueOf(mTaskName.charAt(i)))
                                          .withPrice(price)
                                          .build();
                } else {
                    productInfo = new ProductInfo.Builder()
                                          .withName(String.valueOf(mTaskName.charAt(0)))
                                          .withPrice(price)
                                          .build();
                }
                productList.add(productInfo);
            }
            return new ShoppingTask(mTaskName, productList);
        }

        ShoppingTask buildPhones() {
            return new ShoppingTask(mTaskName, getProductInfoFromJson(MOBILE_PHONES_JSON));
        }

        ShoppingTask buildPuzzles() {
            return new ShoppingTask(mTaskName, getProductInfoFromJson(JIGSAW_PUZZLES_JSON));
        }

        List<ProductInfo> getProductInfoFromJson(String json) {
            List<ProductInfo> productInfos = new ArrayList<>();
            try {
                JSONObject jsonObject = new JSONObject(json);
                JSONArray jsonProducts = jsonObject.getJSONArray("products");
                Log.d("Meil", "products size: " + jsonProducts.length());
                for (int i = 0; i < jsonProducts.length(); i++) {
                    JSONObject jsonProduct = jsonProducts.getJSONObject(i);
                    String name = jsonProduct.getString("name");
                    String price = jsonProduct.getString("price");
                    String url = jsonProduct.getString("url");
                    String imageUrl = jsonProduct.getString("imageUrl");
                    productInfos.add(new ProductInfo.Builder()
                                             .withName(name)
                                             .withUrl(url)
                                             .withImageUrl(imageUrl)
                                             .withPriceStr(price)
                                             .build());
                }
            } catch (JSONException e) {
                Log.e("JsonParser",
                        String.format("There was a problem parsing the JSON\n Details: %s",
                                e.getMessage()));
            }
            return productInfos;
        }
    }
